using Microsoft.EntityFrameworkCore;
using VetClinic.Data;

namespace VetClinic.Services;

public class PetService
{
    private readonly ApplicationDbContext _db;

    public PetService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Pet>> GetAllAsync()
    {
        return await _db.Pets.OrderByDescending(p => p.CreatedAt).ToListAsync();
    }

    public async Task<List<Pet>> SearchAsync(string query)
    {
        if (string.IsNullOrWhiteSpace(query))
            return await GetAllAsync();

        var q = query.ToLower();
        return await _db.Pets
            .Where(p => p.Name.ToLower().Contains(q) || p.OwnerName.ToLower().Contains(q) || p.Species.ToLower().Contains(q))
            .OrderByDescending(p => p.CreatedAt)
            .ToListAsync();
    }

    public async Task<Pet?> GetByIdAsync(int id)
    {
        return await _db.Pets
            .Include(p => p.MedicalRecords.OrderByDescending(m => m.Date))
            .Include(p => p.Appointments.OrderByDescending(a => a.StartTime))
            .FirstOrDefaultAsync(p => p.Id == id);
    }

    public async Task<Pet> CreateAsync(Pet pet)
    {
        pet.CreatedAt = DateTime.UtcNow;
        pet.UpdatedAt = DateTime.UtcNow;
        _db.Pets.Add(pet);
        await _db.SaveChangesAsync();
        return pet;
    }

    public async Task UpdateAsync(Pet pet)
    {
        pet.UpdatedAt = DateTime.UtcNow;
        _db.Pets.Update(pet);
        await _db.SaveChangesAsync();
    }

    public async Task<MedicalRecord> AddMedicalRecordAsync(MedicalRecord record)
    {
        record.CreatedAt = DateTime.UtcNow;
        _db.MedicalRecords.Add(record);
        await _db.SaveChangesAsync();
        return record;
    }

    public async Task<int> GetTotalCountAsync()
    {
        return await _db.Pets.CountAsync();
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;

namespace VetClinic.Services;

public class AppointmentService
{
    private readonly ApplicationDbContext _db;

    public AppointmentService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Appointment>> GetByDateRangeAsync(DateTime start, DateTime end)
    {
        return await _db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= start && a.StartTime < end)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    public async Task<List<Appointment>> GetTodayAsync()
    {
        var today = DateTime.UtcNow.Date;
        return await GetByDateRangeAsync(today, today.AddDays(1));
    }

    public async Task<Appointment?> GetByIdAsync(int id)
    {
        return await _db.Appointments
            .Include(a => a.Pet)
            .FirstOrDefaultAsync(a => a.Id == id);
    }

    public async Task<Appointment> CreateAsync(Appointment appointment)
    {
        appointment.CreatedAt = DateTime.UtcNow;
        appointment.UpdatedAt = DateTime.UtcNow;
        if (appointment.EndTime == default)
            appointment.EndTime = appointment.StartTime.AddMinutes(30);
        _db.Appointments.Add(appointment);
        await _db.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAsync(Appointment appointment)
    {
        appointment.UpdatedAt = DateTime.UtcNow;
        _db.Appointments.Update(appointment);
        await _db.SaveChangesAsync();
    }

    public async Task CancelAsync(int id)
    {
        var appt = await _db.Appointments.FindAsync(id);
        if (appt != null)
        {
            appt.Status = AppointmentStatus.Cancelled;
            appt.UpdatedAt = DateTime.UtcNow;
            await _db.SaveChangesAsync();
        }
    }

    public async Task<List<DateTime>> GetAvailableSlotsAsync(DateTime date)
    {
        var existing = await _db.Appointments
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .Select(a => a.StartTime)
            .ToListAsync();

        var slots = new List<DateTime>();
        var start = date.Date.AddHours(9); // 9 AM
        var end = date.Date.AddHours(17); // 5 PM

        while (start < end)
        {
            if (!existing.Any(e => Math.Abs((e - start).TotalMinutes) < 30))
                slots.Add(start);
            start = start.AddMinutes(30);
        }

        return slots;
    }

    public async Task<int> GetTodayCountAsync()
    {
        var today = DateTime.UtcNow.Date;
        return await _db.Appointments
            .Where(a => a.StartTime.Date == today && a.Status != AppointmentStatus.Cancelled)
            .CountAsync();
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;

namespace VetClinic.Services;

public class BillingService
{
    private readonly ApplicationDbContext _db;

    public BillingService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Invoice>> GetAllAsync(InvoiceStatus? statusFilter = null)
    {
        var query = _db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .AsQueryable();

        if (statusFilter.HasValue)
            query = query.Where(i => i.Status == statusFilter.Value);

        return await query.OrderByDescending(i => i.IssueDate).ToListAsync();
    }

    public async Task<Invoice?> GetByIdAsync(int id)
    {
        return await _db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .Include(i => i.Appointment)
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task<Invoice> CreateAsync(Invoice invoice)
    {
        invoice.InvoiceNumber = $"INV-{DateTime.UtcNow:yyyyMMdd}-{Guid.NewGuid().ToString()[..4].ToUpper()}";
        invoice.IssueDate = DateTime.UtcNow;
        if (invoice.DueDate == default)
            invoice.DueDate = DateTime.UtcNow.AddDays(30);
        _db.Invoices.Add(invoice);
        await _db.SaveChangesAsync();
        return invoice;
    }

    public async Task AddItemAsync(InvoiceItem item)
    {
        _db.InvoiceItems.Add(item);
        await _db.SaveChangesAsync();
    }

    public async Task RemoveItemAsync(int itemId)
    {
        var item = await _db.InvoiceItems.FindAsync(itemId);
        if (item != null)
        {
            _db.InvoiceItems.Remove(item);
            await _db.SaveChangesAsync();
        }
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        payment.PaymentDate = DateTime.UtcNow;
        _db.Payments.Add(payment);

        var invoice = await _db.Invoices.Include(i => i.Items).Include(i => i.Payments).FirstOrDefaultAsync(i => i.Id == payment.InvoiceId);
        if (invoice != null)
        {
            var totalPaid = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
            var totalDue = invoice.Items.Sum(i => i.Quantity * i.UnitPrice);
            if (totalPaid >= totalDue)
                invoice.Status = InvoiceStatus.Paid;
        }

        await _db.SaveChangesAsync();
        return payment;
    }

    public async Task<int> GetPendingCountAsync()
    {
        return await _db.Invoices.Where(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.Overdue).CountAsync();
    }
}

