using Microsoft.EntityFrameworkCore;
using VetClinic.Data;

namespace VetClinic.Services;

public class AppointmentService
{
    private readonly ApplicationDbContext _db;

    public AppointmentService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Appointment>> GetByDateRangeAsync(DateTime start, DateTime end)
    {
        return await _db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= start && a.StartTime < end)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    public async Task<List<Appointment>> GetTodayAsync()
    {
        var today = DateTime.UtcNow.Date;
        return await GetByDateRangeAsync(today, today.AddDays(1));
    }

    public async Task<Appointment?> GetByIdAsync(int id)
    {
        return await _db.Appointments
            .Include(a => a.Pet)
            .FirstOrDefaultAsync(a => a.Id == id);
    }

    public async Task<Appointment> CreateAsync(Appointment appointment)
    {
        appointment.CreatedAt = DateTime.UtcNow;
        appointment.UpdatedAt = DateTime.UtcNow;
        if (appointment.EndTime == default)
            appointment.EndTime = appointment.StartTime.AddMinutes(30);
        _db.Appointments.Add(appointment);
        await _db.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAsync(Appointment appointment)
    {
        appointment.UpdatedAt = DateTime.UtcNow;
        _db.Appointments.Update(appointment);
        await _db.SaveChangesAsync();
    }

    public async Task CancelAsync(int id)
    {
        var appt = await _db.Appointments.FindAsync(id);
        if (appt != null)
        {
            appt.Status = AppointmentStatus.Cancelled;
            appt.UpdatedAt = DateTime.UtcNow;
            await _db.SaveChangesAsync();
        }
    }

    public async Task<List<DateTime>> GetAvailableSlotsAsync(DateTime date)
    {
        var existing = await _db.Appointments
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .Select(a => a.StartTime)
            .ToListAsync();

        var slots = new List<DateTime>();
        var start = date.Date.AddHours(9); // 9 AM
        var end = date.Date.AddHours(17); // 5 PM

        while (start < end)
        {
            if (!existing.Any(e => Math.Abs((e - start).TotalMinutes) < 30))
                slots.Add(start);
            start = start.AddMinutes(30);
        }

        return slots;
    }

    public async Task<int> GetTodayCountAsync()
    {
        var today = DateTime.UtcNow.Date;
        return await _db.Appointments
            .Where(a => a.StartTime.Date == today && a.Status != AppointmentStatus.Cancelled)
            .CountAsync();
    }
}

