@page "/"
@attribute [Authorize]

@inject PetService PetService
@inject AppointmentService AppointmentService
@inject BillingService BillingService
@inject NavigationManager Navigation

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-4">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Total Patients</h5>
                <p class="card-text display-6">@totalPatients</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
            </div>
        </div>
    </div>
</div>

<div class="row">
    <div class="col-md-6">
        <div class="card mb-3">
            <div class="card-header">Quick: Register New Patient</div>
            <div class="card-body">
                <EditForm Model="newPet" OnValidSubmit="AddPet" FormName="quickPet">
                    <DataAnnotationsValidator />
                    <div class="mb-2">
                        <input @bind="newPet.Name" class="form-control" placeholder="Pet Name" />
                    </div>
                    <div class="mb-2">
                        <input @bind="newPet.Species" class="form-control" placeholder="Species" />
                    </div>
                    <div class="mb-2">
                        <input @bind="newPet.OwnerName" class="form-control" placeholder="Owner Name" />
                    </div>
                    <button type="submit" class="btn btn-success">Register Patient</button>
                </EditForm>
                @if (!string.IsNullOrEmpty(petMessage))
                {
                    <div class="alert alert-success mt-2">@petMessage</div>
                }
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card mb-3">
            <div class="card-header">Quick: New Appointment</div>
            <div class="card-body">
                <EditForm Model="newAppointment" OnValidSubmit="AddAppointment" FormName="quickAppt">
                    <div class="mb-2">
                        <select @bind="newAppointment.PetId" class="form-select">
                            <option value="0">Select Patient...</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.OwnerName)</option>
                            }
                        </select>
                    </div>
                    <div class="mb-2">
                        <input type="datetime-local" @bind="newAppointment.StartTime" class="form-control" />
                    </div>
                    <div class="mb-2">
                        <input @bind="newAppointment.Reason" class="form-control" placeholder="Reason" />
                    </div>
                    <button type="submit" class="btn btn-primary">Schedule</button>
                </EditForm>
                @if (!string.IsNullOrEmpty(apptMessage))
                {
                    <div class="alert alert-success mt-2">@apptMessage</div>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private int todayAppointments;
    private int totalPatients;
    private int pendingInvoices;
    private List<Pet> pets = new();
    private Pet newPet = new();
    private Appointment newAppointment = new() { StartTime = DateTime.Now };
    private string? petMessage;
    private string? apptMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        todayAppointments = await AppointmentService.GetTodayCountAsync();
        totalPatients = await PetService.GetTotalCountAsync();
        pendingInvoices = await BillingService.GetPendingCountAsync();
        pets = await PetService.GetAllAsync();
    }

    private async Task AddPet()
    {
        await PetService.CreateAsync(newPet);
        petMessage = $"Patient '{newPet.Name}' registered!";
        newPet = new();
        await LoadData();
    }

    private async Task AddAppointment()
    {
        if (newAppointment.PetId > 0)
        {
            await AppointmentService.CreateAsync(newAppointment);
            apptMessage = "Appointment scheduled!";
            newAppointment = new() { StartTime = DateTime.Now };
            await LoadData();
        }
    }
}

