@page "/patients"
@attribute [Authorize]

@inject PetService PetService
@inject NavigationManager Navigation

<PageTitle>Patients - VetClinic</PageTitle>

<h1>Patients</h1>

<div class="card mb-3">
    <div class="card-header">Add New Patient</div>
    <div class="card-body">
        <EditForm Model="newPet" OnValidSubmit="AddPet" FormName="addPet">
            <DataAnnotationsValidator />
            <ValidationSummary />
            <div class="row">
                <div class="col-md-2 mb-2">
                    <input @bind="newPet.Name" class="form-control" placeholder="Pet Name" />
                </div>
                <div class="col-md-2 mb-2">
                    <input @bind="newPet.Species" class="form-control" placeholder="Species" />
                </div>
                <div class="col-md-2 mb-2">
                    <input @bind="newPet.Breed" class="form-control" placeholder="Breed" />
                </div>
                <div class="col-md-2 mb-2">
                    <input @bind="newPet.OwnerName" class="form-control" placeholder="Owner Name" />
                </div>
                <div class="col-md-2 mb-2">
                    <input @bind="newPet.OwnerPhone" class="form-control" placeholder="Owner Phone" />
                </div>
                <div class="col-md-2 mb-2">
                    <button type="submit" class="btn btn-success w-100">Add</button>
                </div>
            </div>
        </EditForm>
    </div>
</div>

<div class="mb-3">
    <input @bind="searchQuery" @bind:event="oninput" @bind:after="Search" class="form-control" placeholder="Search by name, owner, or species..." />
</div>

<table class="table table-striped table-hover">
    <thead>
        <tr>
            <th>Name</th>
            <th>Species</th>
            <th>Breed</th>
            <th>Owner</th>
            <th>Phone</th>
            <th></th>
        </tr>
    </thead>
    <tbody>
        @foreach (var pet in pets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.OwnerName</td>
                <td>@pet.OwnerPhone</td>
                <td><a href="patients/@pet.Id" class="btn btn-sm btn-outline-primary">View</a></td>
            </tr>
        }
    </tbody>
</table>

@if (!pets.Any())
{
    <p class="text-muted">No patients found.</p>
}

@code {
    private List<Pet> pets = new();
    private Pet newPet = new();
    private string searchQuery = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        pets = await PetService.GetAllAsync();
    }

    private async Task Search()
    {
        pets = await PetService.SearchAsync(searchQuery);
    }

    private async Task AddPet()
    {
        await PetService.CreateAsync(newPet);
        newPet = new();
        await Search();
    }
}

@page "/appointments"
@attribute [Authorize]

@inject AppointmentService AppointmentService
@inject PetService PetService

<PageTitle>Appointments - VetClinic</PageTitle>

<h1>Appointments</h1>

<div class="card mb-4">
    <div class="card-header">Schedule New Appointment</div>
    <div class="card-body">
        <EditForm Model="newAppointment" OnValidSubmit="CreateAppointment" FormName="newAppt">
            <div class="row">
                <div class="col-md-3 mb-2">
                    <label class="form-label">Patient</label>
                    <select @bind="newAppointment.PetId" class="form-select">
                        <option value="0">Select Patient...</option>
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.OwnerName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-2 mb-2">
                    <label class="form-label">Date</label>
                    <input type="date" @bind="selectedDate" @bind:after="LoadSlots" class="form-control" />
                </div>
                <div class="col-md-2 mb-2">
                    <label class="form-label">Time Slot</label>
                    <select @bind="selectedSlot" class="form-select">
                        <option value="">Select...</option>
                        @foreach (var slot in availableSlots)
                        {
                            <option value="@slot.ToString("o")">@slot.ToString("HH:mm")</option>
                        }
                    </select>
                </div>
                <div class="col-md-2 mb-2">
                    <label class="form-label">Veterinarian</label>
                    <input @bind="newAppointment.VeterinarianName" class="form-control" />
                </div>
                <div class="col-md-2 mb-2">
                    <label class="form-label">Reason</label>
                    <input @bind="newAppointment.Reason" class="form-control" />
                </div>
                <div class="col-md-1 mb-2 d-flex align-items-end">
                    <button type="submit" class="btn btn-success">Book</button>
                </div>
            </div>
        </EditForm>
    </div>
</div>

<div class="mb-3">
    <div class="row">
        <div class="col-md-3">
            <label class="form-label">View Week Starting:</label>
            <input type="date" @bind="weekStart" @bind:after="LoadAppointments" class="form-control" />
        </div>
    </div>
</div>

<div class="table-responsive">
    <table class="table table-bordered">
        <thead>
            <tr>
                @for (int i = 0; i < 7; i++)
                {
                    var day = weekStart.AddDays(i);
                    <th class="text-center">@day.ToString("ddd MM/dd")</th>
                }
            </tr>
        </thead>
        <tbody>
            <tr>
                @for (int i = 0; i < 7; i++)
                {
                    var day = weekStart.AddDays(i);
                    var dayAppts = appointments.Where(a => a.StartTime.Date == day.Date).ToList();
                    <td style="min-width:140px; vertical-align:top;">
                        @foreach (var appt in dayAppts)
                        {
                            var badgeClass = appt.Status switch
                            {
                                AppointmentStatus.Scheduled => "bg-primary",
                                AppointmentStatus.Completed => "bg-success",
                                AppointmentStatus.Cancelled => "bg-secondary",
                                _ => "bg-primary"
                            };
                            <div class="badge @badgeClass w-100 mb-1 text-start p-2" style="white-space:normal;">
                                <small>@appt.StartTime.ToString("HH:mm")</small><br/>
                                <strong>@appt.Pet?.Name</strong><br/>
                                <small>@appt.Reason</small>
                                @if (appt.Status == AppointmentStatus.Scheduled)
                                {
                                    <div class="mt-1">
                                        <button class="btn btn-sm btn-light" @onclick="() => CompleteAppointment(appt)">✓</button>
                                        <button class="btn btn-sm btn-light" @onclick="() => CancelAppointment(appt)">✗</button>
                                    </div>
                                }
                            </div>
                        }
                    </td>
                }
            </tr>
        </tbody>
    </table>
</div>

@code {
    private List<Pet> pets = new();
    private List<Appointment> appointments = new();
    private List<DateTime> availableSlots = new();
    private Appointment newAppointment = new();
    private DateTime weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
    private DateTime selectedDate = DateTime.Today;
    private string selectedSlot = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        pets = await PetService.GetAllAsync();
        await LoadAppointments();
        await LoadSlots();
    }

    private async Task LoadAppointments()
    {
        appointments = await AppointmentService.GetByDateRangeAsync(weekStart, weekStart.AddDays(7));
    }

    private async Task LoadSlots()
    {
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(selectedDate);
    }

    private async Task CreateAppointment()
    {
        if (newAppointment.PetId > 0 && !string.IsNullOrEmpty(selectedSlot))
        {
            newAppointment.StartTime = DateTime.Parse(selectedSlot);
            newAppointment.EndTime = newAppointment.StartTime.AddMinutes(30);
            await AppointmentService.CreateAsync(newAppointment);
            newAppointment = new();
            selectedSlot = string.Empty;
            await LoadAppointments();
            await LoadSlots();
        }
    }

    private async Task CompleteAppointment(Appointment appt)
    {
        appt.Status = AppointmentStatus.Completed;
        await AppointmentService.UpdateAsync(appt);
        await LoadAppointments();
    }

    private async Task CancelAppointment(Appointment appt)
    {
        await AppointmentService.CancelAsync(appt.Id);
        await LoadAppointments();
    }
}

@page "/billing"
@attribute [Authorize]

@inject BillingService BillingService
@inject PetService PetService
@inject NavigationManager Navigation

<PageTitle>Billing - VetClinic</PageTitle>

<h1>Billing</h1>

<div class="card mb-4">
    <div class="card-header">Create New Invoice</div>
    <div class="card-body">
        <EditForm Model="newInvoice" OnValidSubmit="CreateInvoice" FormName="newInvoice">
            <div class="row">
                <div class="col-md-3 mb-2">
                    <label class="form-label">Patient</label>
                    <select @bind="newInvoice.PetId" class="form-select">
                        <option value="0">Select Patient...</option>
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.OwnerName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-3 mb-2">
                    <label class="form-label">Due Date</label>
                    <input type="date" @bind="newInvoice.DueDate" class="form-control" />
                </div>
                <div class="col-md-3 mb-2">
                    <label class="form-label">Item Description</label>
                    <input @bind="firstItemDesc" class="form-control" placeholder="e.g. Consultation" />
                </div>
                <div class="col-md-1 mb-2">
                    <label class="form-label">Qty</label>
                    <input type="number" @bind="firstItemQty" class="form-control" />
                </div>
                <div class="col-md-1 mb-2">
                    <label class="form-label">Price</label>
                    <input type="number" step="0.01" @bind="firstItemPrice" class="form-control" />
                </div>
                <div class="col-md-1 mb-2 d-flex align-items-end">
                    <button type="submit" class="btn btn-success">Create</button>
                </div>
            </div>
        </EditForm>
    </div>
</div>

<div class="mb-3">
    <label class="form-label me-2">Filter:</label>
    <select @bind="statusFilter" @bind:after="LoadInvoices" class="form-select d-inline-block" style="width:auto;">
        <option value="">All</option>
        <option value="Pending">Pending</option>
        <option value="Paid">Paid</option>
        <option value="Overdue">Overdue</option>
        <option value="Cancelled">Cancelled</option>
    </select>
</div>

<table class="table table-striped">
    <thead>
        <tr>
            <th>Invoice #</th>
            <th>Patient</th>
            <th>Issue Date</th>
            <th>Due Date</th>
            <th>Total</th>
            <th>Status</th>
            <th></th>
        </tr>
    </thead>
    <tbody>
        @foreach (var inv in invoices)
        {
            var statusClass = inv.Status switch
            {
                InvoiceStatus.Pending => "badge bg-warning",
                InvoiceStatus.Paid => "badge bg-success",
                InvoiceStatus.Overdue => "badge bg-danger",
                InvoiceStatus.Cancelled => "badge bg-secondary",
                _ => "badge bg-secondary"
            };
            <tr>
                <td>@inv.InvoiceNumber</td>
                <td>@inv.Pet?.Name</td>
                <td>@inv.IssueDate.ToShortDateString()</td>
                <td>@inv.DueDate.ToShortDateString()</td>
                <td>$@inv.TotalAmount.ToString("F2")</td>
                <td><span class="@statusClass">@inv.Status</span></td>
                <td><a href="billing/@inv.Id" class="btn btn-sm btn-outline-primary">Detail</a></td>
            </tr>
        }
    </tbody>
</table>

@if (!invoices.Any())
{
    <p class="text-muted">No invoices found.</p>
}

@code {
    private List<Invoice> invoices = new();
    private List<Pet> pets = new();
    private Invoice newInvoice = new() { DueDate = DateTime.Today.AddDays(30) };
    private string firstItemDesc = string.Empty;
    private int firstItemQty = 1;
    private decimal firstItemPrice;
    private string statusFilter = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        pets = await PetService.GetAllAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        InvoiceStatus? filter = string.IsNullOrEmpty(statusFilter) ? null : Enum.Parse<InvoiceStatus>(statusFilter);
        invoices = await BillingService.GetAllAsync(filter);
    }

    private async Task CreateInvoice()
    {
        if (newInvoice.PetId > 0 && !string.IsNullOrWhiteSpace(firstItemDesc))
        {
            newInvoice.Items.Add(new InvoiceItem
            {
                Description = firstItemDesc,
                Quantity = firstItemQty,
                UnitPrice = firstItemPrice
            });
            await BillingService.CreateAsync(newInvoice);
            newInvoice = new() { DueDate = DateTime.Today.AddDays(30) };
            firstItemDesc = string.Empty;
            firstItemQty = 1;
            firstItemPrice = 0;
            await LoadInvoices();
        }
    }
}

