                    <div class="mb-2">
                        <input @bind="newPet.Name" class="form-control" placeholder="Pet Name" />
                    </div>
                    <div class="mb-2">
                        <input @bind="newPet.Species" class="form-control" placeholder="Species" />
                    </div>
                    <div class="mb-2">
