@code {
    private int todayAppointments;
    private int totalPatients;
    private int pendingInvoices;
    private List<Pet> pets = new();
    private Pet newPet = new();
    private Appointment newAppointment = new() { StartTime = DateTime.Now };
    private string? petMessage;
    private string? apptMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        todayAppointments = await AppointmentService.GetTodayCountAsync();
        totalPatients = await PetService.GetTotalCountAsync();
        pendingInvoices = await BillingService.GetPendingCountAsync();
        pets = await PetService.GetAllAsync();
    }

    private async Task AddPet()
    {
        await PetService.CreateAsync(newPet);
        petMessage = $"Patient '{newPet.Name}' registered!";
        newPet = new();
        await LoadData();
    }

    private async Task AddAppointment()
    {
        if (newAppointment.PetId > 0)
        {
            await AppointmentService.CreateAsync(newAppointment);
            apptMessage = "Appointment scheduled!";
            newAppointment = new() { StartTime = DateTime.Now };
            await LoadData();
        }
    }
}

