@page "/patients"
@attribute [Authorize]

@inject PetService PetService
@inject NavigationManager Navigation

<PageTitle>Patients - VetClinic</PageTitle>

<h1>Patients</h1>

<div class="card mb-3">
    <div class="card-header">Add New Patient</div>
    <div class="card-body">
        <EditForm Model="newPet" OnValidSubmit="AddPet" FormName="addPet">
            <DataAnnotationsValidator />
            <ValidationSummary />
            <div class="row">
                <div class="col-md-2 mb-2">
                    <input @bind="newPet.Name" class="form-control" placeholder="Pet Name" />
                </div>
                <div class="col-md-2 mb-2">
                    <input @bind="newPet.Species" class="form-control" placeholder="Species" />
