@page "/appointments"
@attribute [Authorize]

@inject AppointmentService AppointmentService
@inject PetService PetService

<PageTitle>Appointments - VetClinic</PageTitle>

<h1>Appointments</h1>

<div class="card mb-4">
    <div class="card-header">Schedule New Appointment</div>
    <div class="card-body">
        <EditForm Model="newAppointment" OnValidSubmit="CreateAppointment" FormName="newAppt">
            <div class="row">
                <div class="col-md-3 mb-2">
                    <label class="form-label">Patient</label>
                    <select @bind="newAppointment.PetId" class="form-select">
                        <option value="0">Select Patient...</option>
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.OwnerName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-2 mb-2">
                    <label class="form-label">Date</label>
                    <input type="date" @bind="selectedDate" @bind:after="LoadSlots" class="form-control" />
                </div>
                <div class="col-md-2 mb-2">
                    <label class="form-label">Time Slot</label>
                    <select @bind="selectedSlot" class="form-select">
                        <option value="">Select...</option>
                        @foreach (var slot in availableSlots)
                        {
                            <option value="@slot.ToString("o")">@slot.ToString("HH:mm")</option>
                        }
                    </select>
                </div>
                <div class="col-md-2 mb-2">
                    <label class="form-label">Veterinarian</label>
                    <input @bind="newAppointment.VeterinarianName" class="form-control" />
                </div>
                <div class="col-md-2 mb-2">
                    <label class="form-label">Reason</label>
                    <input @bind="newAppointment.Reason" class="form-control" />
                </div>
                <div class="col-md-1 mb-2 d-flex align-items-end">
                    <button type="submit" class="btn btn-success">Book</button>
                </div>
            </div>
        </EditForm>
    </div>
</div>

<div class="mb-3">
    <div class="row">
        <div class="col-md-3">
            <label class="form-label">View Week Starting:</label>
            <input type="date" @bind="weekStart" @bind:after="LoadAppointments" class="form-control" />
        </div>
    </div>
</div>

<div class="table-responsive">
    <table class="table table-bordered">
        <thead>
            <tr>
                @for (int i = 0; i < 7; i++)
                {
                    var day = weekStart.AddDays(i);
                    <th class="text-center">@day.ToString("ddd MM/dd")</th>
                }
            </tr>
        </thead>
        <tbody>
            <tr>
                @for (int i = 0; i < 7; i++)
                {
                    var day = weekStart.AddDays(i);
                    var dayAppts = appointments.Where(a => a.StartTime.Date == day.Date).ToList();
                    <td style="min-width:140px; vertical-align:top;">
                        @foreach (var appt in dayAppts)
                        {
                            var badgeClass = appt.Status switch
                            {
                                AppointmentStatus.Scheduled => "bg-primary",
                                AppointmentStatus.Completed => "bg-success",
                                AppointmentStatus.Cancelled => "bg-secondary",
                                _ => "bg-primary"
                            };
                            <div class="badge @badgeClass w-100 mb-1 text-start p-2" style="white-space:normal;">
                                <small>@appt.StartTime.ToString("HH:mm")</small><br/>
                                <strong>@appt.Pet?.Name</strong><br/>
                                <small>@appt.Reason</small>
                                @if (appt.Status == AppointmentStatus.Scheduled)
                                {
                                    <div class="mt-1">
                                        <button class="btn btn-sm btn-light" @onclick="() => CompleteAppointment(appt)">✓</button>
                                        <button class="btn btn-sm btn-light" @onclick="() => CancelAppointment(appt)">✗</button>
                                    </div>
                                }
                            </div>
                        }
                    </td>
                }
            </tr>
        </tbody>
    </table>
</div>

@code {
    private List<Pet> pets = new();
    private List<Appointment> appointments = new();
    private List<DateTime> availableSlots = new();
    private Appointment newAppointment = new();
    private DateTime weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
    private DateTime selectedDate = DateTime.Today;
    private string selectedSlot = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        pets = await PetService.GetAllAsync();
        await LoadAppointments();
        await LoadSlots();
    }

    private async Task LoadAppointments()
    {
        appointments = await AppointmentService.GetByDateRangeAsync(weekStart, weekStart.AddDays(7));
    }

    private async Task LoadSlots()
    {
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(selectedDate);
    }

    private async Task CreateAppointment()
    {
        if (newAppointment.PetId > 0 && !string.IsNullOrEmpty(selectedSlot))
        {
            newAppointment.StartTime = DateTime.Parse(selectedSlot);
            newAppointment.EndTime = newAppointment.StartTime.AddMinutes(30);
            await AppointmentService.CreateAsync(newAppointment);
            newAppointment = new();
            selectedSlot = string.Empty;
            await LoadAppointments();
            await LoadSlots();
        }
    }

    private async Task CompleteAppointment(Appointment appt)
    {
        appt.Status = AppointmentStatus.Completed;
        await AppointmentService.UpdateAsync(appt);
        await LoadAppointments();
    }

    private async Task CancelAppointment(Appointment appt)
    {
        await AppointmentService.CancelAsync(appt.Id);
        await LoadAppointments();
    }
}

@page "/billing"
@attribute [Authorize]

@inject BillingService BillingService
@inject PetService PetService
@inject NavigationManager Navigation

<PageTitle>Billing - VetClinic</PageTitle>

<h1>Billing</h1>

<div class="card mb-4">
    <div class="card-header">Create New Invoice</div>
    <div class="card-body">
        <EditForm Model="newInvoice" OnValidSubmit="CreateInvoice" FormName="newInvoice">
            <div class="row">
                <div class="col-md-3 mb-2">
                    <label class="form-label">Patient</label>
                    <select @bind="newInvoice.PetId" class="form-select">
                        <option value="0">Select Patient...</option>
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.OwnerName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-3 mb-2">
                    <label class="form-label">Due Date</label>
                    <input type="date" @bind="newInvoice.DueDate" class="form-control" />
                </div>
                <div class="col-md-3 mb-2">
                    <label class="form-label">Item Description</label>
                    <input @bind="firstItemDesc" class="form-control" placeholder="e.g. Consultation" />
