                <div class="col-md-1 mb-2">
                    <label class="form-label">Qty</label>
                    <input type="number" @bind="firstItemQty" class="form-control" />
                </div>
                <div class="col-md-1 mb-2">
                    <label class="form-label">Price</label>
                    <input type="number" step="0.01" @bind="firstItemPrice" class="form-control" />
                </div>
                <div class="col-md-1 mb-2 d-flex align-items-end">
                    <button type="submit" class="btn btn-success">Create</button>
                </div>
            </div>
        </EditForm>
    </div>
</div>

<div class="mb-3">
    <label class="form-label me-2">Filter:</label>
    <select @bind="statusFilter" @bind:after="LoadInvoices" class="form-select d-inline-block" style="width:auto;">
        <option value="">All</option>
        <option value="Pending">Pending</option>
        <option value="Paid">Paid</option>
        <option value="Overdue">Overdue</option>
        <option value="Cancelled">Cancelled</option>
    </select>
</div>

<table class="table table-striped">
    <thead>
        <tr>
            <th>Invoice #</th>
            <th>Patient</th>
            <th>Issue Date</th>
            <th>Due Date</th>
            <th>Total</th>
            <th>Status</th>
            <th></th>
        </tr>
    </thead>
    <tbody>
        @foreach (var inv in invoices)
        {
            var statusClass = inv.Status switch
            {
                InvoiceStatus.Pending => "badge bg-warning",
                InvoiceStatus.Paid => "badge bg-success",
                InvoiceStatus.Overdue => "badge bg-danger",
                InvoiceStatus.Cancelled => "badge bg-secondary",
                _ => "badge bg-secondary"
            };
            <tr>
                <td>@inv.InvoiceNumber</td>
                <td>@inv.Pet?.Name</td>
                <td>@inv.IssueDate.ToShortDateString()</td>
                <td>@inv.DueDate.ToShortDateString()</td>
                <td>$@inv.TotalAmount.ToString("F2")</td>
                <td><span class="@statusClass">@inv.Status</span></td>
                <td><a href="billing/@inv.Id" class="btn btn-sm btn-outline-primary">Detail</a></td>
            </tr>
        }
    </tbody>
</table>

@if (!invoices.Any())
{
    <p class="text-muted">No invoices found.</p>
}

@code {
    private List<Invoice> invoices = new();
    private List<Pet> pets = new();
    private Invoice newInvoice = new() { DueDate = DateTime.Today.AddDays(30) };
    private string firstItemDesc = string.Empty;
    private int firstItemQty = 1;
    private decimal firstItemPrice;
    private string statusFilter = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        pets = await PetService.GetAllAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        InvoiceStatus? filter = string.IsNullOrEmpty(statusFilter) ? null : Enum.Parse<InvoiceStatus>(statusFilter);
        invoices = await BillingService.GetAllAsync(filter);
    }

    private async Task CreateInvoice()
    {
        if (newInvoice.PetId > 0 && !string.IsNullOrWhiteSpace(firstItemDesc))
        {
            newInvoice.Items.Add(new InvoiceItem
            {
                Description = firstItemDesc,
                Quantity = firstItemQty,
                UnitPrice = firstItemPrice
            });
            await BillingService.CreateAsync(newInvoice);
            newInvoice = new() { DueDate = DateTime.Today.AddDays(30) };
            firstItemDesc = string.Empty;
            firstItemQty = 1;
            firstItemPrice = 0;
            await LoadInvoices();
        }
    }
}

