                        <tr>
                            <td>@payment.PaymentDate.ToShortDateString()</td>
                            <td>$@payment.Amount.ToString("F2")</td>
                            <td>@payment.Method</td>
                            <td>@payment.Reference</td>
                            <td>@payment.Notes</td>
                        </tr>
                    }
                </tbody>
            </table>
            @if (!invoice.Payments.Any())
            {
                <p class="text-muted">No payments recorded.</p>
            }

            @if (invoice.Status != InvoiceStatus.Paid)
            {
                <hr />
                <h6>Process Payment</h6>
                <EditForm Model="newPayment" OnValidSubmit="ProcessPayment" FormName="processPayment">
                    <div class="row">
                        <div class="col-md-2 mb-2">
                            <input type="number" step="0.01" @bind="newPayment.Amount" class="form-control" placeholder="Amount" />
                        </div>
                        <div class="col-md-2 mb-2">
                            <select @bind="newPayment.Method" class="form-select">
                                @foreach (var method in Enum.GetValues<PaymentMethod>())
                                {
                                    <option value="@method">@method</option>
                                }
                            </select>
                        </div>
                        <div class="col-md-3 mb-2">
                            <input @bind="newPayment.Reference" class="form-control" placeholder="Reference" />
                        </div>
                        <div class="col-md-3 mb-2">
                            <input @bind="newPayment.Notes" class="form-control" placeholder="Notes" />
                        </div>
                        <div class="col-md-2 mb-2">
                            <button type="submit" class="btn btn-primary">Pay</button>
                        </div>
                    </div>
                </EditForm>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private InvoiceItem newItem = new() { Quantity = 1 };
    private Payment newPayment = new();

    private string StatusBadge => invoice?.Status switch
    {
        InvoiceStatus.Pending => "bg-warning",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        invoice = await BillingService.GetByIdAsync(Id);
    }

    private async Task AddItem()
    {
        if (invoice != null && !string.IsNullOrWhiteSpace(newItem.Description))
        {
            newItem.InvoiceId = invoice.Id;
            await BillingService.AddItemAsync(newItem);
            newItem = new() { Quantity = 1 };
            await LoadInvoice();
        }
    }

    private async Task RemoveItem(int itemId)
    {
        await BillingService.RemoveItemAsync(itemId);
        await LoadInvoice();
    }

    private async Task ProcessPayment()
    {
        if (invoice != null && newPayment.Amount > 0)
        {
            newPayment.InvoiceId = invoice.Id;
            await BillingService.ProcessPaymentAsync(newPayment);
            newPayment = new();
            await LoadInvoice();
        }
    }
}

